/**
 * Dashbook — Figma Code Connect templates (canonical 10)
 * =======================================================
 *
 * Maps the canonical-10 Figma component sets in the Dashbook library file
 * (fileKey 91csAF1OGUmCZROdZlCRSv) to their `@dashfi/svelte` code, so Figma
 * Dev Mode shows the real import + props instead of autogenerated CSS.
 *
 * STATUS / GATE — not yet publishable:
 *   - Code Connect requires a Figma **Organization or Enterprise** plan.
 *     The dashfi team is currently on **Professional**, so `figma connect
 *     publish` will not work until the plan is upgraded.
 *   - The component sets must also be **published to a team library** first
 *     (a Figma-UI action; the Plugin API cannot publish).
 *   - Final home: these belong next to the component source in
 *     `core/libs/svelte-components/lib/` once the lib is published. They live
 *     here as authored templates that travel with the handoff.
 *
 * Prop mappings below are derived from FIGMA_HANDOFF.md §5 and the component
 * APIs in `@dashfi/svelte`. Verify the `@figma/code-connect` import specifier
 * and the Svelte example syntax against the installed CLI version before
 * publishing (Svelte support shape has shifted across releases).
 */
import figma, { html } from '@figma/code-connect/html'

const FILE = 'https://www.figma.com/design/91csAF1OGUmCZROdZlCRSv/Dashbook'

/* Button — node 24:44 — props: Variant, State */
figma.connect(`${FILE}?node-id=24-44`, {
  props: {
    variant: figma.enum('Variant', {
      default: 'default',
      brand: 'brand',
      destructive: 'destructive',
      secondary: 'secondary',
      outline: 'outline',
      ghost: 'ghost',
      link: 'link',
    }),
    disabled: figma.enum('State', { disabled: true }),
  },
  imports: ["import { Button } from '@dashfi/svelte/ui/button'"],
  example: ({ variant, disabled }) =>
    html`<Button variant=${variant} disabled=${disabled}>Button</Button>`,
})

