/* Dialog — node 29:29 (DialogContent) — prop: Size */
figma.connect(`${FILE}?node-id=29-29`, {
  props: {
    size: figma.enum('Size', { sm: 'sm', default: 'default', lg: 'lg' }),
  },
  imports: [
    "import { Dialog, DialogContent, DialogTitle, DialogDescription, DialogFooter } from '@dashfi/svelte/ui/dialog'",
  ],
  example: ({ size }) =>
    html`<DialogContent size=${size}>
  <DialogTitle>Dialog title</DialogTitle>
  <DialogDescription>A short description.</DialogDescription>
  <DialogFooter>
    <Button variant="ghost">Cancel</Button>
    <Button variant="brand">Confirm</Button>
  </DialogFooter>
</DialogContent>`,
})

/* Card — node 29:53 — props: Has header, Has footer (compound composition) */
figma.connect(`${FILE}?node-id=29-53`, {
  props: {
    hasHeader: figma.boolean('Has header'),
    hasFooter: figma.boolean('Has footer'),
  },
  imports: [
    "import { Card, CardHeader, CardTitle, CardDescription, CardContent, CardFooter } from '@dashfi/svelte/ui/card'",
  ],
  example: ({ hasHeader, hasFooter }) =>
    html`<Card>
  ${hasHeader
    ? html`<CardHeader><CardTitle>Card title</CardTitle><CardDescription>Card description</CardDescription></CardHeader>`
    : ''}
  <CardContent>Card content sits here.</CardContent>
  ${hasFooter ? html`<CardFooter><Button variant="brand">Action</Button></CardFooter>` : ''}
</Card>`,
})
